// // This comment suggests that z should be 0 when r[1:0] is 10, but it actually sets z to 1.
module top_module (
    input [1:0] r,
    output reg z
);

    always @(*) begin
        case (r)
            2'b00: z = 1;
            2'b01: z = 1;
            2'b10: z = 0;
            2'b11: z = 1;
            default: z = 0; // Default case
        endcase
    end
endmodule
